class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        Arrays.sort(time);
        double res = 0;
        int i = n - 1;
        int stage = 0;
        while (i >= 0) {
            int cnt = Math.min(k, i + 1);
            double maxTime = 0;
            for (int j = 0; j < cnt; j++) {
                maxTime = Math.max(maxTime, time[i - j]);
            }
            res += maxTime * mul[stage % m];
            stage = (stage + (int) Math.floor(maxTime * mul[stage % m])) % m;
            i -= cnt;
        }
        return res;
    }
}
```
